wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(12458024361679286544)
,p_name=>'Event Revenue'
,p_static_id=>'event-revenue'
,p_title=>'Event Revenue Report'
,p_template=>4073835273271169698
,p_display_sequence=>30
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_new_grid_row=>false
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT e.event_id,',
'       e.title,',
'       e.location,',
'       e.capacity,',
'       NVL(SUM(p.amount), 0) AS total_revenue',
'  FROM ETMS_EVENT e',
'  LEFT JOIN ETMS_TICKET t  ON e.event_id = t.event_id',
'  LEFT JOIN ETMS_BOOKING b ON t.ticket_id = b.ticket_id',
'  LEFT JOIN ETMS_PAYMENT p ON b.booking_id = p.booking_id',
' GROUP BY e.event_id, e.title, e.location, e.capacity'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
